var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CCN No. TPM002L000071-04\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 인터뷰","JPN":"CCN No. TPM002L000071-04\\n<color=#ffd34c>3級要人</color>閲覧承認資料\\n付録：インタビュー","ENG":"[[","TWN":"CCN No.TPM002L000071-04\\n<color=#ffd34c>3級要員</color> 閱覽審批資料\\n附錄採訪","THA":"CCN หมายเลข TPM002L000071-04\\n<color=#ffd34c>ระดับปล่อยผ่าน 3</color> ข้อมูลลับ\\nภาคผนวก: บทสัมภาษณ์","VTN":"CCN Số TPM002L000071-04\\n<color=#ffd34c>Cấp Độ An Ninh III</color> Thông Tin Tối Mật\\nPhụ lục: Phỏng Vấn","SCN":"CCN No.TPM002L000071-04\\n<color=#ffd34c>3级要人</color> 阅览审批资料\\n附录采访","DEU":"CCN-Nr. TPM002L000071-04\\n<color=#ffd34c>Freigabestufe\xA0III</color> Verschlusssache\\nAnhang: Interview","FRA":"CCN No. TPM002L000071-04\\n<color=#ffd34c>Sécurité niveau III</color> Information confidentielle\\nAnnexe\xA0: Entretien"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 얼마 전에 들어온 꼬마 경정님이요?","JPN":"あ、この前入ってきた子供の警視ですか？","ENG":"Oh you mean the recently recruited little Major?","TWN":"喔，前陣子來的小不點警正啊？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"처음 카운터 능력자가 신입으로 왔다고 했을 땐 다들 관심이 많았어요.","JPN":"初めてカウンター能力者が新米として入ってきた時は、みんな興味津々でした。","ENG":"Everyone was interested at first because we hired a Counter.","TWN":"第一次有個制裁能力者的新人加入，大家都對她非常感興趣。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"경찰서에서 보기 드문 학생인데다, 채용되자 마자 경정 발령이라니, 이목이 쏠릴 수 밖에 없잖아요?","JPN":"警察署では珍しい学生ですし、採用されてすぐ警視に任命だなんて、注目を集めるしかありませんね。","ENG":"Not only is she a minor, but she was made a Major as soon as she was hired. Obviously she's attracted a lot of attention.","TWN":"畢竟在警察署很難得會有學生，而且一上任馬上就當上警正，這能不受到大家矚目嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"어느 학교 다니다 왔냐, 어쩌다가 경찰에 지원했냐, 이런저런 질문이 쏟아졌죠.","JPN":"どの学校の出身か、どうして警察に志願したのか、多くの質問が寄せられました。","ENG":"So everyone asked her all sorts of questions, like what school she attended and why she decided to join the force.","TWN":"我們問了她很多問題，比如在哪個學校上學啦，為什麼要當警察之類的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런데 그때 처음으로 나온 대답이......","JPN":"なのに、その時初めて言い出した答えが……","ENG":"But then her first response was...","TWN":"那時她的第一句回答是……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>개인 사생활에 쏟을 관심이 있으면 가서 밀린 수사나 하세요. 이 무능력자들!</color>","JPN":"<color=#ffd34c>個人のプライベートに興味を持つ時間があるなら、溜まった捜査でもしなさい。この無能ども！</color>","ENG":"<color=#ffd34c>If you've got the time and energy to pry about my personal life, just go catch up on your investigations. You incompetents!</color>","TWN":"<color=#ffd34c>對個人隱私這麼感興趣的話，就自己去調查啊。你們這群無能力者!</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......이었어요.","JPN":"……でした。","ENG":"That's what she said.","TWN":"……她是這麼說的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그 차가운 표정에 분위기는 당연히 어색해졌죠.","JPN":"その冷たい表情を見て、しんと静まり返ったんです。","ENG":"Such a harsh response obviously made things awkward.","TWN":"當時的氣氛一度非常尷尬。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"엄청 고지식한 성격에, 자존감 높은 카운터라니.","JPN":"とても生真面目な性格で、プライドの高いカウンターだなんて。","ENG":"I can't imagine having to deal with such a cocky young Counter.","TWN":"固執的性格加上極高的自尊心。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"소영 씨가 많이 고생 하겠구나 싶더군요.","JPN":"マエカワさんも大変だろうな、と思いました。","ENG":"So I thought poor Soyoung must have her hands full.","TWN":"我還以為姜小姐就夠嗆的了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런데 그건 괜한 걱정이었죠.","JPN":"でも、それは余計な心配でした。","ENG":"But it turns out I was getting worried for nothing.","TWN":"但後來我發現這擔心是多餘的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"실제론 오히려 경정님이 소영 씨한테 휘둘리고 있더라고요.","JPN":"実際は、むしろ警視のほうがマエカワさんに振り回されていたんです。","ENG":"In fact, the Major's the one getting bossed around by Soyoung.","TWN":"因為她被姜小姐耍得團團轉呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"뭐, 남들이 보기엔 소영 씨가 꼬마 경정님한테 굽신굽신 하는 것처럼 보이겠지만......","JPN":"まぁ、他人から見ると、マエカワさんが子供の警視にぺこぺこしているように見えるかもしれませんが……","ENG":"Of course, at a glance it may appear like Soyoung is being all subservient to the little Major...","TWN":"雖然在外人眼中看來，姜小姐對小不點警正一副卑躬屈膝的模樣……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"실상은 전혀 그렇지 않아요.","JPN":"実は全然そうじゃありません。","ENG":"But that couldn't be farther from the truth.","TWN":"但實際情況完全相反。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"한 번은 소영 씨가 <color=#ffd34c>경정님은 초보경찰이니까 이런 건 못 하시죠?</color> 라고 하니까,","JPN":"ある日、マエカワさんが<color=#ffd34c>「警視様は新米警官だから、こんなことできませんよね？」</color>と言い出したら、","ENG":"One time, Soyoung said, <color=#ffd34c>\\"You probably don't know how to do this since you're a novice cop, right ma'am?\\"</color> to the Major.","TWN":"有次姜小姐對她說， <color=#ffd34c>警正大人妳還只是個新手，所以不太懂這類的工作吧？</color>之後，"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"경정님이 발끈해서 사흘 내내 서류철을 끼고 야근공부를 하시더라고요.","JPN":"癪に障ったのか、3日間ずっと書類を持ち出して夜遅くまで勉強してました。","ENG":"This got the Major so furious that she spent the next three nights studying regulations.","TWN":"結果被激怒的警正帶著檔案夾連三天加班苦讀。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};